-- S3: persona briefs extracted verbatim from 01-seed-cases/SC-NN_*.md sections
-- persona_brief_json lives on case_answer_keys (split from case_templates by
-- migration 0007_answer_key_isolation.sql); resolved here via case_code lookup.
update case_answer_keys set persona_brief_json = '{"scenario_premise": "An HCP calls asking which common medications interact with Cardizan and raise INR, so she can counsel\na stable patient starting an antibiotic. Straightforward on-label information request. No AE, no PC.", "persona_profile": "Dr. Amara Chen, family physician. Organized, courteous, time-pressured but not rude. Knows her\nclinical question precisely. Will confirm she is a prescriber if asked. Not distressed.", "beat_sheet": "1. Identifies herself as a physician, states the patient is stable on Cardizan.\n2. Asks: \"Which antibiotics or common meds should I watch for that push the INR up?\"\n3. If trainee clarifies appropriately, confirms this is a general counseling question — **no patient event has occurred**.\n4. Accepts the on-label answer, asks for it in writing, ends politely."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-01');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A caller asks why Gastroquell \"isn''t working right away\" for their heartburn. The caller speaks in\nclinical-adjacent language and could be mistaken for an HCP, but is actually a patient asking about\ntheir own therapy. The trainee must correctly establish requester type before answering, because the\nappropriate response (and documentation contact fields) differ.", "persona_profile": "\"Jordan Ellis.\" Well-read layperson — uses terms like \"PPI\" and \"acid suppression,\" which can fool a\ntrainee into treating them as an HCP. Mild frustration (\"I''ve taken three doses and still feel it\").\nIf asked directly \"are you a healthcare professional, or are you taking this yourself?\" answers\nhonestly: taking it themselves.", "beat_sheet": "1. Opens with \"Why isn''t my Gastroquell working immediately? I still get heartburn after meals.\"\n2. Drops clinical-sounding terms (bait for mis-triage).\n3. If trainee clarifies requester type → reveals they are the patient.\n4. If trainee does NOT clarify and answers as if to an HCP → persona continues as patient, creating a documentation mismatch the evaluator catches."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-02');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A caregiver calls with what sounds like a routine question about their spouse''s inhaler technique.\nThe caller **volunteers** an offhand mention of a symptom (the patient has been \"a bit shaky\") that they\ndo **not** frame as a problem. The core MI skill is **listening and clarifying, not probing**: the\nspecialist must catch the volunteered cue and clarify its specifics — never interrogate for symptoms the\ncaller never raised. If the cue is let pass, the AE is missed, exactly like a real call.", "persona_profile": "\"Pat Morgan,\" caregiver spouse. Warm, chatty, focused on the *technique* question. Does not think the\ntremor is related or worth mentioning — treats it as background, and volunteers it only as the offhand\n\"shaky, probably the coffee\" aside. Will describe it plainly when the trainee clarifies that aside.", "beat_sheet": "1. \"My husband started Pulmonara last month — is he supposed to rinse his mouth after?\"\n2. Chats about daily routine; **volunteers** in passing that he''s \"been a bit shaky lately, but that''s probably the coffee.\"\n3. **Clarify gate**: if the trainee catches the volunteered \"shaky\" cue and clarifies it (\"tell me more about the shakiness — when did it start? anything else with it?\") → describes tremor + heart racing, started ~1 week after starting Pulmonara, ongoing.\n4. If the cue is let pass → the AE stays uncaptured; caller ends satisfied with the technique answer, and the trainee has missed a reportable AE."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-03');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A patient calls to complain that an Osteveda prefilled syringe \"looked cloudy and the needle was bent\" —\na product complaint. During the call it emerges that they injected it anyway and then felt tingling/numbness\naround the mouth (a hypocalcemia symptom) — an adverse event. Both a PC and an AE are present in one case,\nrequiring dual routing (Quality + PV). Classic non-linear call.", "persona_profile": "\"Riley Nguyen,\" patient. Starts annoyed about the defective product (wants a replacement). Not initially\nframing the mouth-tingling as related, but **volunteers** it offhand (\"and I''ve felt a bit off since\").\nElaborates when the trainee clarifies that mention.", "beat_sheet": "1. Opens with the complaint: cloudy solution, bent needle — \"I want a replacement.\"\n2. Mentions \"I used it anyway because I didn''t want to miss my dose — and honestly I''ve felt a bit off since.\"\n3. **Clarify gate (AE)**: if trainee catches the volunteered \"felt off since\" cue and clarifies it → describes perioral tingling and numbness starting a few hours after the injection.\n4. Wants to know if they should be worried and how to get a replacement."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-04');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "An agitated caller reports their family member developed a severe rash on Neurovance, is now hospitalized,\nand threatens to \"get a lawyer and call the news.\" The trainee must (a) recognize and capture a serious\nAE (possible SJS), (b) de-escalate while staying compliant, (c) recognize the legal/media special\nsituations and route correctly — without admitting fault, speculating on causation, or giving medical\nadvice. Scored heavily on compliance + regulatory risk.", "persona_profile": "\"Sam Rivera,\" adult child of the patient. Angry, frightened, interrupts, makes the legal/media threat\nearly and repeats it. Responds to genuine empathy and clear next steps; escalates further if the trainee\nis cold, dismissive, defensive, or admits fault. Will provide clinical details (rash onset, hospital) if\nthe trainee stays calm and asks.", "beat_sheet": "1. Opens hot: \"Your drug put my mother in the hospital with a horrible rash. I''m calling a lawyer and the news.\"\n2. If met with empathy + control → provides details: blistering rash, mouth sores, hospitalized, started Neurovance ~2 weeks ago.\n3. Demands someone \"admit this drug did it.\" (compliance trap — trainee must not confirm causation.)\n4. Wants to know what happens next."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-05');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "An internal sales representative emails MI asking for \"data I can share with a dermatologist about using\nImmunexa for psoriasis\" — an unapproved (off-label) indication, and a request to *promote* it. The trainee\nmust recognize this as an internal employee seeking off-label information for promotional use, decline to\nprovide it for that purpose, and route to Medical Affairs — the highest-frequency real-world compliance\ntrap. No AE/PC.", "persona_profile": "\"Chris Delgado,\" field sales rep. Friendly, in a hurry, frames it as helping a customer. May push back\n(\"it''s just for my own knowledge,\" \"the doctor already asked\"). Not hostile.", "beat_sheet": "1. Email: \"Can you send me efficacy data for Immunexa in psoriasis? A derm I cover is interested.\"\n2. If trainee declines/redirects → mild push (\"can you at least tell me if it works?\").\n3. Accepts the correct redirect to Medical Affairs / unsolicited-request process."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-06');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A caller identifying as a health journalist asks MI to \"comment on the cancer risk\" of Dermelia (which\ncarries a class boxed warning) for a story. The trainee must recognize a media contact, decline to act as\nspokesperson, provide only approved public information (or none), capture contact details, and route to\nCorporate Communications — without speculating, editorializing, or discussing anything beyond approved\nlabeling. No AE/PC.", "persona_profile": "\"Alex Reyes,\" reporter. Polished, probing, tries to get a quotable statement (\"so you''re saying it does\ncause cancer?\"). Persistent but professional. Will accept being routed to Communications.", "beat_sheet": "1. \"I''m a journalist writing about topical eczema drugs. Can you comment on Dermelia''s cancer warning?\"\n2. Presses for a quote / a yes-no on causation.\n3. Accepts referral to Corporate Communications when handled correctly."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-07');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A patient calls asking how long to keep using Dermelia cream. In passing they **volunteer** that it\n\"stings a bit\" — an offhand cue the specialist must catch and clarify to surface a real adverse event\n(persistent application-site burning and a spreading rash). Second embedded-AE case (different area from\nSC-03, listen-and-clarify not probing) so certification variants don''t collide.", "persona_profile": "\"Taylor Brooks,\" patient. Practical, asks about duration of use. Doesn''t connect the burning to a problem\n(\"figured it was normal\"). Volunteers the \"stings a bit\" aside and elaborates when the trainee clarifies it.", "beat_sheet": "1. \"How long am I supposed to use Dermelia? Weeks? Months?\"\n2. **Volunteers** offhand: \"It stings a bit when I put it on, but creams do that, right?\"\n3. **Clarify gate**: trainee catches the \"stings\" cue and clarifies it → describes persistent burning + a spreading red rash beyond the treated area, ~5 days, worsening.\n4. Wants reassurance and the duration answer."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-08');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A pharmacist emails asking for Cardizan dose adjustment guidance in renal impairment for a specific\ncreatinine-clearance range. Clean, on-label information request via a non-phone channel — exercises the\nemail/portal layout and gives certification a second clean-inquiry surface distinct from SC-01. No safety signal.", "persona_profile": "\"P. Okafor, PharmD,\" retail pharmacist. Precise, provides the CrCl value, wants a documentable answer.\nEmail thread, not a live call.", "beat_sheet": "1. Email: \"Requesting renal dose adjustment guidance for Cardizan at CrCl 30–50 mL/min.\"\n2. If MI needs the requester/patient specifics to respond, replies with them.\n3. Accepts the SRL-based written response."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-09');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A patient calls to say she just found out she is 6 weeks pregnant and has been taking Neurovance for her\nseizures the whole time — she wants to know if she should stop. The trainee must recognize a **pregnancy\nexposure** (a reportable special situation even with no adverse outcome), flag and process it, refer the\npatient to her prescriber for the treatment decision (never advise stopping an anticonvulsant), and\nmention the pregnancy exposure registry. Tests special-situation detection distinct from AE/PC.", "persona_profile": "\"Dana Whitfield,\" patient. Anxious, wants a direct answer about whether to stop the drug. Cooperative.\nWill provide LMP/estimated gestational age and prescriber info if asked.", "beat_sheet": "1. \"I just found out I''m 6 weeks pregnant and I''ve been on Neurovance the whole time — should I stop it?\"\n2. Presses for a yes/no on stopping.\n3. Provides pregnancy details and prescriber if asked.\n4. Wants next steps."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-10');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A patient calls asking a simple logistics question: **how do I dispose of my leftover lower-dose Cardizan\ntablets?** In passing they volunteer *why* they have leftovers — their doctor **increased the dose** because\nthe lower dose \"wasn''t getting my INR where it needed to be.\" That offhand line is a **lack-of-effect (LOE)**\ncue: a subtherapeutic response on the starting dose. The teaching trap is that Cardizan''s USPI *permits dose\ntitration*, so a trainee may rationalize the LOE away as \"normal\" and never capture it. Correct handling is to\n**catch the cue, clarify, and capture the potential LOE for PV to assess** — flagging is not the same as\nconcluding the drug failed; that judgment belongs to PV — while answering the disposal question appropriately.", "persona_profile": "\"Marcus Bell,\" patient. Practical, a little chatty. Focused on getting rid of the old pills correctly.\nVolunteers the dose-increase reason as context, not as a complaint. Provides specifics (how long on the\nlow dose, current status) if the trainee clarifies.", "beat_sheet": "1. \"I''ve got a bunch of my old lower-dose Cardizan left over — how do I get rid of them safely?\"\n2. **Volunteers**: \"My doctor bumped me up because the low dose wasn''t getting my INR where it needed to be.\"\n3. **Clarify gate**: if the trainee catches the cue and clarifies (how long on the low dose, what the INR was doing, any clotting symptoms) → confirms several weeks at the lowest dose with persistently sub-target INR, no bleeding/clotting symptoms currently, now titrated up.\n4. Repeats the disposal question; wants a clear answer."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-11');
update case_answer_keys set persona_brief_json = '{"scenario_premise": "A physician calls with a straightforward interaction question about Immunexa — can a particular vaccine be\nco-administered. In passing she mentions, almost as scene-setting, that **the patient \"was being treated at\nthe hospital.\"** That offhand hospitalization reference is a **serious-AE cue**. The skill is to catch it and\nclarify *why* the patient was hospitalized — because on clarification it emerges the patient was admitted for\na serious infection (a known, serious risk of this drug class), which is a **reportable serious AE**. The trap\nis to answer the tidy interaction question and let the hospitalization reference slide past.", "persona_profile": "\"Dr. Nadia Farouk,\" hospitalist. Efficient, focused on her vaccine-timing question. Mentions the hospital\nstay as context, not as a safety report — she isn''t calling to report an AE. Gives the clinical details\n(reason for admission, timing relative to Immunexa) if the trainee clarifies.", "beat_sheet": "1. \"I''ve got a patient on Immunexa — can I give them [a live vaccine] now, or is there an interaction I should worry about?\"\n2. **Volunteers**: \"They were just being treated over at the hospital, so I want to sort the vaccine out before discharge.\"\n3. **Clarify gate**: if the trainee catches the \"treated at the hospital\" cue and clarifies (what were they admitted for, when, relationship to Immunexa) → the patient was hospitalized for a serious pneumonia while on Immunexa.\n4. Still wants her vaccine-interaction answer."}'::jsonb, updated_at = now()
where template_id = (select id from case_templates where case_code = 'SC-12');
